Clear(colCdsMarketMaterialItemTest);
ClearCollect(
    colCdsMarketSegmentsIds,
    Distinct('Market Segments', 'Market Segment')
);
ForAll(
    colCdsMarketSegmentsIds,
    Collect(
        colCdsMarketMaterialItemTest,
        Filter(
            'Market Material Items',
            'Market Segment'.'Market Segment'= colCdsMarketSegmentsIds[@Value]
        )
    )
)

// Get list of unique window choices for any jobs currently on the device
ClearCollect(
    colWindowChoices_ForJobsOnDevice,
    Distinct(
        AddColumns(
            colCdsJobEntries,
            WindowChoiceID,
            'Window Choice'.'Window Choice'
        ).WindowChoiceID,
        WindowChoiceID
    )
);
// Add a column for the job entry option headers to the window choices
ClearCollect(
    colJobEntryOptionHeaders_ForJobsOnDevice,
    Distinct(
        AddColumns(
            colWindowChoices_ForJobsOnDevice,
            HeaderID,
            LookUp(
                colCdsWindowChoices,
                'Window Choice' = Value,
                'Job Entry Option (Header)'
            ).'Job Entry Option'
        ).HeaderID,
        HeaderID
    )
);
// Determine whether a new set of Job Entry Options must be downloaded to the device
Set(
    gblShouldAppDownloadJobEntryOptions,
    false in AddColumns(
        colJobEntryOptionHeaders_ForJobsOnDevice,
        OnDevice,
        Value in colCdsJobEntryOptions.'Job Entry Option'
    ).OnDevice
);
// Loop through each column header and download its child options
If(
    gblShouldAppDownloadJobEntryOptions,
    ForAll(
        colJobEntryOptionHeaders_ForJobsOnDevice As currentRecord,
        // Get header record
        Collect(
            colCdsJobEntryOptions,
            Filter(
                'Job Entry Options',
                'Job Entry Option'=currentRecord.Value,
                Status=gblOptionSets.JobEntryOption.Status.Active,
                'Legacy?'=gblOptionSets.JobEntryOption.IsLegacy.No
            )
        );
        // Get attributes, hierarchy steps and values
        Collect(
            colCdsJobEntryOptions,
            Filter(
                'Job Entry Options',
                'Job Entry Option (Header Root)'.'Job Entry Option'=currentRecord.Value,
                Status=gblOptionSets.JobEntryOption.Status.Active,
                'Legacy?'=gblOptionSets.JobEntryOption.IsLegacy.No
            )
        )
    );
    UpdateContext({locSaveJobEntryOptions: true});
);
Clear(colWindowChoices_ForJobsOnDevice);
Clear(colJobEntryOptionHeaders_ForJobsOnDevice);
Set(gblShouldAppDownloadJobEntryOptions, false)
